// --- BREAK-EVEN ---
function updateRatioLabel() {
    const v = parseInt(document.getElementById('ioSlider').value);
    document.getElementById('ratioLabel').textContent = `${v}% input / ${100-v}% output`;
}

function onModelChange() {
    const m = BEDROCK_MODELS[document.getElementById('beModel').value];
    const sel = document.getElementById('selfInst');
    sel.value = m.recInst;
    document.getElementById('recBadge').textContent = '⭐ recommended auto-selected';
    setTimeout(() => document.getElementById('recBadge').textContent = '', 3000);
}

function calcBreakeven() {
    const m = BEDROCK_MODELS[document.getElementById('beModel').value];
    const inst = INSTANCES[document.getElementById('selfInst').value];
    const inputPct = parseInt(document.getElementById('ioSlider').value) / 100;
    const outputPct = 1 - inputPct;
    const monthlyCost = inst.hourly * 730;
    const blendedPer1M = m.input * inputPct + m.output * outputPct;
    const breakevenM = monthlyCost / blendedPer1M;
    const breakevenTokens = breakevenM * 1_000_000;

    const el = document.getElementById('breakevenResult');
    el.style.display = 'block';
    el.innerHTML = `<h3>Break-Even Analysis</h3>
        <div class="rec-item"><span class="rec-label">Bedrock Model</span><span class="rec-value">${m.provider} ${m.model}</span></div>
        <div class="rec-item"><span class="rec-label">Blended Rate (${(inputPct*100).toFixed(0)}% in / ${(outputPct*100).toFixed(0)}% out)</span><span class="rec-value">$${blendedPer1M.toFixed(3)} / 1M tokens</span></div>
        <div class="rec-item"><span class="rec-label">Self-Host Instance</span><span class="rec-value">${inst.name} @ $${monthlyCost.toFixed(0)}/mo</span></div>
        <div class="rec-item"><span class="rec-label" style="color:var(--color-warning)">Break-Even Point</span><span class="rec-value warn">${breakevenM.toFixed(1)}M tokens/month</span></div>
        <div class="rec-item"><span class="rec-label">≈ Requests (500 tok avg)</span><span class="rec-value">${(breakevenTokens/500).toLocaleString(undefined,{maximumFractionDigits:0})} requests/mo</span></div>
        <p style="margin-top:12px;font-size:0.82rem;color:var(--color-text-muted);">
            If you process <strong>more</strong> than ${breakevenM.toFixed(1)}M tokens/month, self-hosting on ${inst.name} is cheaper.<br>
            If you process <strong>less</strong>, Bedrock on-demand is more cost-effective (plus zero ops overhead).
        </p>`;

