input.newStr:
function calcBreakeven() {
    const m = BEDROCK_MODELS[document.getElementById('beModel').value];
    const inst = INSTANCES[document.getElementById('selfInst').value];
    const inputPct = parseInt(document.getElementById('ioSlider').value) / 100;
    const outputPct = 1 - inputPct;
    const monthlyCost = inst.hourly * 730;
    const blendedPer1M = m.input * inputPct + m.output * outputPct;
    const breakevenM = monthlyCost / blendedPer1M;
    const breakevenTokens = breakevenM * 1_000_000;

    // Estimate VRAM needed (FP16 × 1.6 overhead, MoE active params ~25%)
    const paramStr = m.params;
    let paramNum = parseFloat(paramStr);
    const isMoE = paramStr.includes('MoE');
    const memNeeded = isMoE ? (paramNum * 0.25 * 2 * 1.6) : (paramNum * 2 * 1.6);
    const memDiff = inst.vramGB - memNeeded;
    const memOk = memDiff >= 0;

    let memWarning = '';
    if (!memOk) {
        memWarning = `<div style="margin-top:16px;padding:14px;background:rgba(248,113,113,0.1);border:1px solid rgba(248,113,113,0.3);border-radius:10px;">
            <span style="color:#f87171;font-weight:700;"><i class="bi bi-exclamation-triangle-fill"></i> Memory Warning</span>
            <p style="color:#fca5a5;font-size:0.82rem;margin-top:6px;">
                Estimated VRAM needed: <strong>${memNeeded.toFixed(0)} GB</strong> (FP16 + overhead) — Instance has only <strong>${inst.vramGB} GB</strong>.<br>
                <strong>Deficit: ${Math.abs(memDiff).toFixed(0)} GB.</strong> Use a larger instance, quantization (INT8/INT4), or tensor parallelism.
            </p>
        </div>`;
    } else {
        memWarning = `<div style="margin-top:16px;padding:14px;background:rgba(52,211,153,0.08);border:1px solid rgba(52,211,153,0.2);border-radius:10px;">
            <span style="color:#6ee7b7;font-weight:700;"><i class="bi bi-check-circle-fill"></i> Memory OK</span>
            <span style="color:var(--color-text-muted);font-size:0.82rem;margin-left:8px;">
                ~${memNeeded.toFixed(0)} GB needed / ${inst.vramGB} GB available (${memDiff.toFixed(0)} GB headroom)
            </span>
        </div>`;
    }

    const el = document.getElementById('breakevenResult');
    el.style.display = 'block';
    el.innerHTML = `<h3><i class="bi bi-graph-up-arrow"></i> Break-Even Analysis</h3>
        <div class="rec-item"><span class="rec-label"><i class="bi bi-cloud"></i> Bedrock Model</span><span class="rec-value">${m.provider} ${m.model}</span></div>
        <div class="rec-item"><span class="rec-label"><i class="bi bi-percent"></i> Blended Rate (${(inputPct*100).toFixed(0)}% in / ${(outputPct*100).toFixed(0)}% out)</span><span class="rec-value">$${blendedPer1M.toFixed(3)} / 1M tokens</span></div>
        <div class="rec-item"><span class="rec-label"><i class="bi bi-server"></i> Self-Host Instance</span><span class="rec-value">${inst.name} @ $${monthlyCost.toFixed(0)}/mo</span></div>
        <div class="rec-item"><span class="rec-label" style="color:var(--color-warning)"><i class="bi bi-bullseye"></i> Break-Even Point</span><span class="rec-value warn">${breakevenM.toFixed(1)}M tokens/month</span></div>
        <div class="rec-item"><span class="rec-label"><i class="bi bi-chat-dots"></i> ≈ Requests (500 tok avg)</span><span class="rec-value">${(breakevenTokens/500).toLocaleString(undefined,{maximumFractionDigits:0})} req/mo</span></div>
        ${memWarning}
        <p style="margin-top:14px;font-size:0.82rem;color:var(--color-text-muted);line-height:1.6;">
            <i class="bi bi-arrow-right-circle" style="color:var(--color-success)"></i> <strong>More</strong> than ${breakevenM.toFixed(1)}M tokens/month → self-hosting is cheaper.<br>
            <i class="bi bi-arrow-right-circle" style="color:var(--color-accent)"></i> <strong>Less</strong> → Bedrock on-demand wins (zero ops overhead).
        </p>`;

