        .rec-value { font-weight: 700; font-size: 0.88rem; color: #c7d2fe; }
        .rec-item i { color: var(--color-pink); }

        .breakdown { margin-top: 20px; padding: 18px; background: rgba(0,0,0,0.25); border-radius: var(--radius-sm); border: 1px solid var(--color-border); }
        .breakdown h4 { color: var(--color-text-muted); margin-bottom: 10px; font-size: 0.85rem; display: flex; align-items: center; gap: 6px; }
        .breakdown p { color: var(--color-text-muted); line-height: 1.8; font-size: 0.84rem; }

        /* Pricing table */
        .table-wrapper { overflow-x: auto; margin-top: 16px; border-radius: var(--radius-sm); border: 1px solid var(--color-border); }
        .pricing-table { width: 100%; border-collapse: collapse; font-size: 0.82rem; }
        .pricing-table th {
            padding: 14px 14px; text-align: left;
            background: var(--color-surface-2);
            color: var(--color-accent-light); font-weight: 700; font-size: 0.72rem;
            text-transform: uppercase; letter-spacing: 0.5px;
            border-bottom: 1px solid var(--color-border-strong);
        }
        .pricing-table td { padding: 12px 14px; border-bottom: 1px solid var(--color-border); }
        .pricing-table tr:hover td { background: var(--color-accent-dim); }
        .pricing-table .highlight { color: #6ee7b7; font-weight: 700; text-shadow: 0 0 8px rgba(110,231,183,0.3); }
        .pricing-table .warn { color: #fbbf24; font-weight: 700; text-shadow: 0 0 8px rgba(251,191,36,0.3); }

        .note { color: var(--color-text-muted); font-size: 0.78rem; margin-top: 16px; display: flex; align-items: center; gap: 6px; }

        /* Break-even */
        .breakeven-box {
            background: linear-gradient(135deg, rgba(16,185,129,0.08), rgba(52,211,153,0.04));
            border: 1px solid var(--color-border-strong); border-radius: 14px; padding: 24px; margin-top: 24px;
        }
        .breakeven-box h3 { color: var(--color-accent-light); margin-bottom: 16px; display: flex; align-items: center; gap: 8px; }
        .breakeven-box .rec-value { color: #c7d2fe; }
        .breakeven-box .warn { color: #fb923c; text-shadow: 0 0 10px rgba(251,146,60,0.4); }

        /* Footer */
        .footer { text-align: center; margin-top: 48px; color: var(--color-text-muted); font-size: 0.8rem; padding: 24px 0; border-top: 1px solid var(--color-border); }

        @media (max-width: 700px) {
            .form-grid, .result-grid { grid-template-columns: 1fr; }
            h1 { font-size: 2rem; }
            .container { padding: 24px 16px; }
            .card { padding: 20px; }
            .tabs { flex-direction: column; }
            .pricing-table { font-size: 0.72rem; }
            .pricing-table th, .pricing-table td { padding: 8px 6px; }
        }
    </style>
</head>
